   161→/**
   162→ * Default note values
   163→ */
   164→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   165→  const now = new Date();
   166→  return {
   167→    id: uuidv4(),
   168→    folderId: null,
   169→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   170→    content: '', // Empty Lexical state
   171→    contentText: '',
   172→    tags: [],
   173→    createdAt: now,
   174→    updatedAt: now,
   175→    isPinned: false,
   176→    isArchived: false,
   177→    ...overrides,
   178→  };
   179→};
   180→
   181→/**
   182→ * Sort notes based on sort config
   183→ */
   184→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   185→  const sorted = [...notes];
   186→
   187→  sorted.sort((a, b) => {
   188→    let comparison = 0;
   189→
   190→    switch (config.field) {
   191→      case 'title':
   192→        comparison = a.title.localeCompare(b.title);
   193→        break;
   194→      case 'createdAt':
   195→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   196→        break;
   197→      case 'updatedAt':
   198→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   199→        break;
   200→      case 'manual':
   201→        // Manual sort - preserve order (could add sortOrder field in future)
   202→        comparison = 0;
   203→        break;
   204→    }
   205→
   206→    return config.order === 'asc' ? comparison : -comparison;
   207→  });
   208→
   209→  // Always pin pinned notes to top
   210→  return sorted.sort((a, b) => {
   211→    if (a.isPinned && !b.isPinned) return -1;
   212→    if (!a.isPinned && b.isPinned) return 1;
   213→    return 0;
   214→  });
   215→};
   216→
   217→/**
   218→ * Filter notes based on filter type
   219→ */
   220→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   221→  switch (filter) {
   222→    case 'favorites':
   223→      return notes.filter((note) => note.isFavorite);
   224→    case 'pinned':
   225→      return notes.filter((note) => note.isPinned);
   226→    case 'archived':
   227→      return notes.filter((note) => note.isArchived);
   228→    case 'unarchived':
   229→      return notes.filter((note) => !note.isArchived);
   230→    case 'all':
   231→    default:
   232→      return notes;
   233→  }
   234→};
