   272→          log.warn('Note not found', { id });
   273→          return;
   274→        }
   275→
   276→        // Only update timestamp if content/title/tags actually changed
   277→        // Skip timestamp update for UI-only changes (like folderId without content change)
   278→        const shouldUpdateTimestamp =
   279→          updates.content !== undefined ||
   280→          updates.title !== undefined ||
   281→          updates.tags !== undefined;
   282→
   283→        set((state) => ({
   284→          notes: {
   285→            ...state.notes,
   286→            [id]: {
   287→              ...note,
   288→              ...updates,
   289→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   290→            },
   291→          },
   292→        }));
   293→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   294→      },
   295→
   296→      deleteNote: (id) => {
   297→        // Save note for undo
   298→        const noteToDelete = get().notes[id];
   299→        if (!noteToDelete) {
   300→          log.warn('Note not found', { id });
   301→          return;
   302→        }
   303→
   304→        // Store the previous activeNoteId for undo
   305→        const wasActive = get().activeNoteId === id;
   306→
   307→        // Delete the note
   308→        set((state) => {
   309→          const { [id]: deleted, ...remainingNotes } = state.notes;
   310→          return {
   311→            notes: remainingNotes,
   312→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   313→          };
   314→        });
   315→
   316→        log.debug('Note deleted', { id });
   317→
   318→        // Delete associated images from IndexedDB (async, fire-and-forget)
   319→        import('../services/indexedDB').then(({ indexedDBService }) => {
   320→          indexedDBService.deleteNoteImages(id).catch((err) => {
   321→            log.error('Failed to delete note images', { id, error: err });
   322→          });
   323→        });
   324→
   325→        // Add undo action
   326→        useUndoStore.getState().addUndoAction(
   327→          `Note "${noteToDelete.title}" deleted`,
   328→          () => {
   329→            // Restore the note
   330→            set((state) => ({
   331→              notes: {
   332→                ...state.notes,
   333→                [id]: noteToDelete,
   334→              },
   335→              activeNoteId: wasActive ? id : state.activeNoteId,
   336→            }));
   337→            log.debug('Note restored (undo)', { id });
   338→          }
   339→        );
   340→      },
   341→
   342→      duplicateNote: (id) => {
