   796→              ...note,
   797→              tags: uniqueTags,
   798→              updatedAt: new Date(),
   799→            };
   800→          }
   801→        });
   802→
   803→        if (Object.keys(updatedNotes).length > 0) {
   804→          set((state) => ({
   805→            notes: {
   806→              ...state.notes,
   807→              ...updatedNotes,
   808→            },
   809→          }));
   810→          log.info('Tag replaced', { oldTag, newTag, count: Object.keys(updatedNotes).length });
   811→        }
   812→      },
   813→
   814→      // UI state
   815→      setActiveNote: (id) => {
   816→        set({ activeNoteId: id });
   817→        log.debug('Active note set', { id });
   818→      },
   819→
   820→      setSortConfig: (config) => {
   821→        set({ sortConfig: config });
   822→        log.debug('Sort config updated', { config });
   823→      },
   824→
   825→      setFilter: (filter) => {
   826→        set({ filter });
   827→        log.debug('Filter updated', { filter });
   828→      },
   829→
   830→      // Utility
   831→      getNoteCount: () => {
   832→        return Object.keys(get().notes).length;
   833→      },
   834→
   835→      getNotesInFolder: (folderId) => {
   836→        return Object.values(get().notes).filter(
   837→          (note) => note.folderId === folderId
   838→        );
   839→      },
   840→
   841→      exportNotes: () => {
   842→        return Object.values(get().notes);
   843→      },
   844→
   845→      importNotes: (notes, merge) => {
   846→        if (!merge) {
   847→          // Replace all notes
   848→          set({
   849→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   850→            activeNoteId: null,
   851→          });
   852→          log.info('Imported notes', { count: notes.length, mode: 'replace' });
   853→        } else {
   854→          // Merge with existing notes
   855→          set((state) => {
   856→            const updatedNotes = { ...state.notes };
   857→            notes.forEach((note) => {
   858→              updatedNotes[note.id] = note;
   859→            });
   860→            return { notes: updatedNotes };
   861→          });
   862→          log.info('Imported notes', { count: notes.length, mode: 'merge' });
   863→        }
   864→      },
   865→
   866→      clearAllNotes: () => {
   867→        set({ notes: {}, activeNoteId: null });
   868→        log.info('All notes cleared');
   869→      },
   870→
   871→      // ==================== BACKLINKS (Phase 4) ====================
   872→
   873→      getBacklinks: (noteId: string) => {
   874→        const state = get();
   875→        const note = state.notes[noteId];
   876→        if (!note) return [];
   877→
   878→        return getBacklinksUtil(noteId, note.title, state.notes);
   879→      },
   880→
   881→      updateLinkedNotes: (noteId: string, content: string) => {
   882→        const state = get();
   883→        const linkTitles = extractWikiLinks(content);
   884→        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   885→
   886→        set((currentState) => {
   887→          const note = currentState.notes[noteId];
   888→          if (!note) return currentState;
   889→
   890→          return {
   891→            notes: {
   892→              ...currentState.notes,
   893→              [noteId]: {
   894→                ...note,
   895→                linkedNotes: linkedNoteIds,
   896→              },
   897→            },
   898→          };
   899→        });
   900→      },
   901→
   902→      // ==================== TEMPLATES (Phase 4) ====================
   903→
   904→      getNoteTemplates: () => {
   905→        return DEFAULT_NOTE_TEMPLATES;
   906→      },
   907→
   908→      createNoteFromTemplate: (templateId: string) => {
   909→        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   910→        if (!template) return null;
   911→
   912→        const newNote = createDefaultNote({
   913→          title: template.name,
   914→          contentText: template.description,
   915→          tags: template.defaultTags || [],
   916→          icon: template.icon,
   917→        });
   918→
   919→        set((state) => ({
   920→          notes: {
   921→            ...state.notes,
   922→            [newNote.id]: newNote,
   923→          },
   924→          activeNoteId: newNote.id,
   925→        }));
   926→
   927→        log.debug('Created note from template', { template: template.name });
   928→        return newNote;
   929→      },
   930→
   931→      // ==================== DAILY NOTES ====================
   932→
   933→      getDailyNote: (date: Date) => {
   934→        const state = get();
   935→        const settings = useSettingsStore.getState().dailyNotes;
   936→        return getDailyNoteUtil(date, state.notes, settings);
   937→      },
   938→
   939→      createDailyNote: (date: Date) => {
   940→        const settings = useSettingsStore.getState().dailyNotes;
   941→        const newNote = createDailyNoteUtil(date, settings);
   942→
   943→        set((state) => ({
   944→          notes: {
   945→            ...state.notes,
   946→            [newNote.id]: newNote,
   947→          },
   948→          activeNoteId: newNote.id,
   949→        }));
   950→
   951→        log.info('Created daily note', { date: newNote.title, id: newNote.id });
   952→        return newNote;
   953→      },
   954→
   955→      getOrCreateDailyNote: (date: Date) => {
   956→        const state = get();
   957→        const settings = useSettingsStore.getState().dailyNotes;
   958→
   959→        // Try to find existing note
   960→        const existingNote = getDailyNoteUtil(date, state.notes, settings);
   961→        if (existingNote) {
   962→          // Set as active note
   963→          set({ activeNoteId: existingNote.id });
   964→          log.debug('Found existing daily note', { date: existingNote.title });
   965→          return existingNote;
   966→        }
   967→
   968→        // Create new note
   969→        const newNote = createDailyNoteUtil(date, settings);
   970→        set((currentState) => ({
   971→          notes: {
   972→            ...currentState.notes,
   973→            [newNote.id]: newNote,
   974→          },
   975→          activeNoteId: newNote.id,
   976→        }));
   977→
   978→        log.info('Auto-created daily note', { date: newNote.title, id: newNote.id });
   979→        return newNote;
   980→      },
   981→
   982→      // ==================== P2: BLOCK-LEVEL LINKS & HOVER PREVIEW ====================
   983→
   984→      getBlockContent: (noteId: string, blockId: string) => {
   985→        const note = get().notes[noteId];
   986→        if (!note) return null;
   987→
   988→        const blockInfo = findBlockInContent(note.contentText, blockId);
   989→        return blockInfo ? blockInfo.content : null;
   990→      },
   991→
   992→      getNotePreview: (noteId: string, blockId?: string) => {
   993→        const note = get().notes[noteId];
   994→        if (!note) return null;
   995→
   996→        return createNotePreview(note, blockId);
   997→      },
   998→    }),
   999→    {
  1000→      name: 'notes', // IndexedDB key
  1001→      storage: createJSONStorage(() => createSyncedStorage()),
  1002→      partialize: (state) => ({
  1003→        // Only persist notes, not UI state
  1004→        notes: state.notes,
  1005→      }),
  1006→      // Handle date serialization
  1007→      onRehydrateStorage: () => (state) => {
  1008→        log.debug('Notes store rehydrating');
  1009→        if (state) {
  1010→          try {
  1011→            // Ensure notes object exists and is valid
  1012→            if (state.notes && typeof state.notes === 'object') {
  1013→              // Convert date strings back to Date objects
  1014→              Object.values(state.notes).forEach((note) => {
  1015→                if (typeof note.createdAt === 'string') {
  1016→                  note.createdAt = new Date(note.createdAt);
  1017→                }
  1018→                if (typeof note.updatedAt === 'string') {
  1019→                  note.updatedAt = new Date(note.updatedAt);
  1020→                }
  1021→              });
  1022→            } else {
  1023→              log.warn('Corrupted notes data detected, resetting to empty');
  1024→              state.notes = {};
  1025→            }
  1026→          } catch (err) {
  1027→            log.error('Error during notes store rehydration', { error: err });
  1028→            // Reset to safe defaults
  1029→            state.notes = {};
  1030→            state.activeNoteId = null;
  1031→          }
  1032→        }
  1033→        log.info('Notes store rehydrated');
  1034→      },
  1035→    }
  1036→  )
  1037→);
  1038→
  1039→/**
  1040→ * Selector hooks for optimized re-renders
  1041→ */
  1042→export const useActiveNote = () =>
  1043→  useNotesStore((state) => {
  1044→    const activeId = state.activeNoteId;
  1045→    return activeId ? state.notes[activeId] : null;
  1046→  });
  1047→
