   130→export function findUnlinkedMentions(
   131→  targetNoteId: string,
   132→  targetNoteTitle: string,
   133→  allNotes: Record<string, Note>
   134→): UnlinkedMention[] {
   135→  const mentions: UnlinkedMention[] = [];
   136→
   137→  // Skip if title is too short (avoid false positives)
   138→  if (targetNoteTitle.length < 3) return mentions;
   139→
   140→  const notesArray = Object.values(allNotes);
   141→
   142→  // Create regex for word-boundary matching (avoid partial matches)
   143→  // Escape special regex characters in title
   144→  const escapedTitle = targetNoteTitle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
   145→  const titlePattern = new RegExp(`\\b${escapedTitle}\\b`, 'gi');
