   159→      const position = match.index;
   160→      const matchText = match[0];
   161→
   162→      // Check if this match is inside [[brackets]] (already linked)
   163→      const beforeMatch = content.substring(Math.max(0, position - 2), position);
   164→      const afterMatch = content.substring(position + matchText.length, position + matchText.length + 2);
   165→
   166→      // Skip if surrounded by [[ ]]
   167→      if (beforeMatch === '[[' && afterMatch === ']]') continue;
   168→
   169→      // Extract context (50 chars before/after)
   170→      const contextStart = Math.max(0, position - 50);
   171→      const contextEnd = Math.min(content.length, position + matchText.length + 50);
   172→      let context = content.substring(contextStart, contextEnd);
